solution:
function windowSums(a, k) {
  const out = [];
  for (let i = 0; i + k <= a.length; i++) {
    let s = 0;
    for (let j = i; j < i + k; j++) s += a[j];
    out.push(s);
  }
  return out;
}

tests:
if (JSON.stringify(windowSums([1, 2, 3, 4], 2)) !== JSON.stringify([3, 5, 7])) throw new Error('windows');
if (JSON.stringify(windowSums([1, 2, 3], 3)) !== JSON.stringify([6])) throw new Error('k=n');
if (JSON.stringify(windowSums([1], 3)) !== JSON.stringify([])) throw new Error('k>n');
